import{_ as d,o as a,c as e,a0 as s}from"./chunks/framework.jwovEGr5.js";const b=JSON.parse('{"title":"第 27 章 行业路线图：从通用能力到行业工作流 ​","description":"","frontmatter":{},"headers":[],"relativePath":"p4/27.md","filePath":"p4/27.md"}'),r={name:"p4/27.md"};function n(h,t,l,i,p,o){return a(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="第-27-章-行业路线图-从通用能力到行业工作流-​" tabindex="-1">第 27 章 行业路线图：从通用能力到行业工作流 ​ <a class="header-anchor" href="#第-27-章-行业路线图-从通用能力到行业工作流-​" aria-label="Permalink to &quot;第 27 章 行业路线图：从通用能力到行业工作流 ​&quot;">​</a></h1><p>行业方案不是把“生成周报、做 PPT”换一个行业名称。真正的行业化至少包含四层：行业对象、专业流程、系统与数据、责任和监管边界。</p><h2 id="识别行业场景的五个问题-​" tabindex="-1">识别行业场景的五个问题 ​ <a class="header-anchor" href="#识别行业场景的五个问题-​" aria-label="Permalink to &quot;识别行业场景的五个问题 ​&quot;">​</a></h2><ol><li>工作对象是什么：订单、设备、病例、合同、课程还是内容素材？</li><li>流程由哪些岗位和系统共同完成？</li><li>哪些字段、口径或版本必须保持一致？</li><li>错误会造成什么后果，谁拥有最终责任？</li><li>哪一步最重复、最耗时，又最容易人工验收？</li></ol><p>只有第五类步骤适合作为首批 AI 试点。</p><h2 id="制造业-​" tabindex="-1">制造业 ​ <a class="header-anchor" href="#制造业-​" aria-label="Permalink to &quot;制造业 ​&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>flowchart LR</span></span>
<span class="line"><span>    A[设备/生产/质检记录] --&gt; B[归集与字段校验]</span></span>
<span class="line"><span>    B --&gt; C[异常与趋势分析]</span></span>
<span class="line"><span>    C --&gt; D[日报/周报/质量报告]</span></span>
<span class="line"><span>    D --&gt; E[人工确认与闭环]</span></span></code></pre></div><table tabindex="0"><thead><tr><th>场景</th><th>输入</th><th>交付物</th><th>专业约束</th></tr></thead><tbody><tr><td>生产报表</td><td>ERP 导出、班组表、停机记录</td><td>产量、良率、停机原因</td><td>班次、物料、工序口径一致</td></tr><tr><td>质量记录</td><td>检验表、图片、标准规范</td><td>缺陷分类、异常批次、报告草稿</td><td>不代替质量放行</td></tr><tr><td>设备知识</td><td>手册、维修记录、故障代码</td><td>排障建议、备件清单</td><td>安全操作和停机权限</td></tr><tr><td>供应链周报</td><td>订单、库存、交期</td><td>风险清单、催办建议</td><td>数据时点和供应商权限</td></tr></tbody></table><h2 id="跨境电商-​" tabindex="-1">跨境电商 ​ <a class="header-anchor" href="#跨境电商-​" aria-label="Permalink to &quot;跨境电商 ​&quot;">​</a></h2><p>跨境电商的难点不是单一内容生成，而是多平台、多语言、多币种、多时区和多规则并存。</p><table tabindex="0"><thead><tr><th>场景</th><th>WorkBuddy 工作流</th><th>验收重点</th></tr></thead><tbody><tr><td>商品上新</td><td>产品资料 → 卖点 → 多语种草稿 → 平台格式</td><td>参数、禁用词、商标和本地表达</td></tr><tr><td>客服与评价</td><td>工单聚类 → 回复草稿 → FAQ 更新</td><td>订单事实、退款承诺、语气</td></tr><tr><td>经营复盘</td><td>订单/广告/库存 → 统一口径 → 利润与异常</td><td>汇率、时区、归因窗口</td></tr><tr><td>供应链协同</td><td>采购、交期、物流 → 风险清单</td><td>单号、时间、责任人</td></tr></tbody></table><h2 id="金融、咨询与财税-​" tabindex="-1">金融、咨询与财税 ​ <a class="header-anchor" href="#金融、咨询与财税-​" aria-label="Permalink to &quot;金融、咨询与财税 ​&quot;">​</a></h2><p>这类行业的核心资产是证据、分析口径和专业判断。AI 适合缩短资料处理时间，不适合隐藏来源后直接给结论。</p><table tabindex="0"><thead><tr><th>场景</th><th>基础版</th><th>进阶版</th><th>人工关口</th></tr></thead><tbody><tr><td>行业研究</td><td>来源表和资料摘要</td><td>证据矩阵、定期跟踪</td><td>观点与投资含义</td></tr><tr><td>咨询项目</td><td>访谈纪要、材料盘点</td><td>假设树、分析底稿、报告</td><td>建议与客户承诺</td></tr><tr><td>财税材料</td><td>单据识别、字段核对</td><td>申报资料清单、差异检查</td><td>申报和税务判断</td></tr><tr><td>经营分析</td><td>多表汇总</td><td>指标解释、异常归因</td><td>会计口径和管理决策</td></tr></tbody></table><h2 id="医疗医药-​" tabindex="-1">医疗医药 ​ <a class="header-anchor" href="#医疗医药-​" aria-label="Permalink to &quot;医疗医药 ​&quot;">​</a></h2><p>医疗医药强调证据等级、版本控制、隐私和专业资质。首批场景应避开诊断和治疗决定。</p><table tabindex="0"><thead><tr><th>场景</th><th>可由 AI 辅助</th><th>不应自动完成</th></tr></thead><tbody><tr><td>文献整理</td><td>检索结果去重、摘要、证据表</td><td>临床结论和治疗建议</td></tr><tr><td>生产质量</td><td>批记录完整性检查、培训材料</td><td>批次放行和偏差定责</td></tr><tr><td>医学/市场材料</td><td>来源核对、禁用表述提示</td><td>宣传合规最终批准</td></tr><tr><td>内部知识</td><td>制度问答、版本定位</td><td>超权限访问患者或试验数据</td></tr></tbody></table><h2 id="文化传媒与广告-​" tabindex="-1">文化传媒与广告 ​ <a class="header-anchor" href="#文化传媒与广告-​" aria-label="Permalink to &quot;文化传媒与广告 ​&quot;">​</a></h2><p>视频团队案例已经展示了多 Agent 内容流水线。行业落地时，还需要在创作效率之外加入版权、品牌和发布控制。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>flowchart LR</span></span>
<span class="line"><span>    A[热点与客户 brief] --&gt; B[选题评分]</span></span>
<span class="line"><span>    B --&gt; C[脚本与分镜]</span></span>
<span class="line"><span>    C --&gt; D[素材与制作]</span></span>
<span class="line"><span>    D --&gt; E[事实/版权/品牌审核]</span></span>
<span class="line"><span>    E --&gt; F[人工发布]</span></span>
<span class="line"><span>    F --&gt; G[数据复盘]</span></span></code></pre></div><p>可沉淀资产，品牌语气、禁用词、事实来源库、授权素材库、平台格式模板、选题评分表、脚本 Skill、分镜模板和复盘指标。</p><h2 id="教育与培训-​" tabindex="-1">教育与培训 ​ <a class="header-anchor" href="#教育与培训-​" aria-label="Permalink to &quot;教育与培训 ​&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>输入</th><th>交付物</th><th>约束</th></tr></thead><tbody><tr><td>企业培训</td><td>制度、课程、案例</td><td>学习路径、课件、题库</td><td>版本和适用人群</td></tr><tr><td>教学备课</td><td>课程标准、教材、学情</td><td>教案、活动、练习</td><td>知识准确和年龄适配</td></tr><tr><td>学习反馈</td><td>作业、评分规则</td><td>共性问题、反馈草稿</td><td>不用敏感特征贴标签</td></tr><tr><td>招生内容</td><td>批准的课程资料</td><td>页面和咨询话术草稿</td><td>不夸大效果和承诺</td></tr></tbody></table><h2 id="建筑装饰与科技服务-​" tabindex="-1">建筑装饰与科技服务 ​ <a class="header-anchor" href="#建筑装饰与科技服务-​" aria-label="Permalink to &quot;建筑装饰与科技服务 ​&quot;">​</a></h2><p>这类行业以项目为单位，材料多、版本多、责任链长。WorkBuddy 适合做资料盘点、标书初稿、合同差异和项目周报。</p><table tabindex="0"><thead><tr><th>场景</th><th>交付物</th><th>风险控制</th></tr></thead><tbody><tr><td>招投标</td><td>响应矩阵、材料清单、标书初稿</td><td>逐条对应招标文件，不虚构资质</td></tr><tr><td>方案设计</td><td>需求摘要、方案结构、汇报材料</td><td>专业计算和图纸需资质人员确认</td></tr><tr><td>项目管理</td><td>纪要、进度、风险和变更清单</td><td>版本、签字和责任主体可追溯</td></tr><tr><td>合同与报价</td><td>条款差异、报价表检查</td><td>金额、税率和承诺人工复核</td></tr></tbody></table>`,26)])])}const u=d(r,[["render",n]]);export{b as __pageData,u as default};
